jQuery(document).ready(function($) {
    // --- Model Fetching Logic ---
    function syncProviderUI(providerSelectElement) {
        var $providerSelect = $(providerSelectElement);
        var variation = $providerSelect.data('variation');
        var selectedProvider = $providerSelect.val();
        var $variationWrapper = $providerSelect.closest('.inside');
        var $apiKeyWrapper = $variationWrapper.find('.api-key-wrapper[data-variation="' + variation + '"]');
        $apiKeyWrapper.find('.api-key-input').hide();
        var $providerInputWrapper = $apiKeyWrapper.find('.api-key-input[data-provider="' + selectedProvider + '"]');
        $providerInputWrapper.show();
        var $apiKeyInput = $providerInputWrapper.find('.quorlyx-api-key-input');
        if ($apiKeyInput.val()) {
            fetchModelsForProvider(variation, selectedProvider, $apiKeyInput.val());
        } else {
            handleModelFetchError($('.quorlyx-model-select[data-variation="' + variation + '"]'), 'Enter API key to fetch models.');
        }
    }

    function fetchModelsForProvider(variation, provider, apiKey) {
        var $modelSelect = $('.quorlyx-model-select[data-variation="' + variation + '"]');
        var $spinner = $modelSelect.next('.quorlyx-model-spinner');
        $spinner.addClass('is-active');
        $modelSelect.prop('disabled', true).empty().append('<option>Fetching models...</option>');
        $.ajax({
            url: quorlyxAdmin.restUrl + 'fetch-models',
            method: 'POST',
            contentType: 'application/json',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: JSON.stringify({
                provider: provider,
                api_key: apiKey
            })
        }).done(function(response) {
            if (response.success && response.models.length) {
                $modelSelect.empty();
                var savedModel = $modelSelect.data('saved-model') || '';
                var isSavedModelPresent = false;
                response.models.forEach(function(model) {
                    var isRecommended = model.name.toLowerCase().includes('recommended');
                    var optionText = model.name;
                    var $option = $('<option>', {
                        value: model.id,
                        text: optionText
                    });
                    if (model.id === savedModel) {
                        $option.prop('selected', true);
                        isSavedModelPresent = true
                    }
                    $modelSelect.append($option)
                });
                if (!isSavedModelPresent && savedModel) {
                    $modelSelect.append($('<option>', {
                        value: savedModel,
                        text: savedModel,
                        selected: true
                    }))
                }
                if (!isSavedModelPresent && response.models.some(m => m.name.toLowerCase().includes('recommended'))) {
                    $modelSelect.val($modelSelect.find('option:contains(Recommended)').val())
                }
            } else {
                handleModelFetchError($modelSelect, 'No compatible models found.')
            }
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Could not fetch models.';
            handleModelFetchError($modelSelect, message)
        }).always(function() {
            $spinner.removeClass('is-active');
            $modelSelect.prop('disabled', false)
        })
    }

    function handleModelFetchError($modelSelect, message) {
        var savedModel = $modelSelect.data('saved-model') || '';
        $modelSelect.empty();
        if (savedModel) {
            $modelSelect.append($('<option>', {
                value: savedModel,
                text: savedModel
            }))
        }
        $modelSelect.append($('<option>', {
            value: '',
            disabled: true,
            selected: !savedModel
        }).text(message))
    }

    function getRoutingApiKey(provider) {
        var $input = $('.api-key-wrapper[data-variation="a"] .api-key-input[data-provider="' + provider + '"] .quorlyx-api-key-input');
        return $input.length ? $input.val() : ''
    }

    function fetchModelsForRouting(provider, apiKey) {
        var $modelSelect = $('.quorlyx-routing-model-select');
        if (!$modelSelect.length) {
            return
        }
        var $spinner = $modelSelect.next('.quorlyx-routing-model-spinner');
        $spinner.addClass('is-active');
        $modelSelect.prop('disabled', true).empty().append('<option>Fetching models...</option>');
        $.ajax({
            url: quorlyxAdmin.restUrl + 'fetch-models',
            method: 'POST',
            contentType: 'application/json',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: JSON.stringify({
                provider: provider,
                api_key: apiKey
            })
        }).done(function(response) {
            if (response.success && response.models.length) {
                $modelSelect.empty();
                var savedModel = $modelSelect.data('saved-model') || '';
                var isSavedModelPresent = false;
                response.models.forEach(function(model) {
                    var optionText = model.name;
                    var $option = $('<option>', {
                        value: model.id,
                        text: optionText
                    });
                    if (model.id === savedModel) {
                        $option.prop('selected', true);
                        isSavedModelPresent = true
                    }
                    $modelSelect.append($option)
                });
                if (!isSavedModelPresent && savedModel) {
                    $modelSelect.append($('<option>', {
                        value: savedModel,
                        text: savedModel,
                        selected: true
                    }))
                }
            } else {
                handleModelFetchError($modelSelect, 'No compatible models found.')
            }
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Could not fetch models.';
            handleModelFetchError($modelSelect, message)
        }).always(function() {
            $spinner.removeClass('is-active');
            $modelSelect.prop('disabled', false)
        })
    }

    function initRoutingModelFetch() {
        var $providerSelect = $('.quorlyx-routing-provider-select');
        if (!$providerSelect.length) return;
        var provider = $providerSelect.val();
        if (!provider) {
            handleModelFetchError($('.quorlyx-routing-model-select'), 'Select a provider to fetch models.');
            return
        }
        var apiKey = getRoutingApiKey(provider);
        if (!apiKey) {
            handleModelFetchError($('.quorlyx-routing-model-select'), 'Enter API key for this provider to fetch models.');
            return
        }
        fetchModelsForRouting(provider, apiKey)
    }

    function imageModeIsIndependent() {
        var $mode = $('#quorlyx_image_generator_ai_mode');
        return !$mode.length || $mode.val() === 'independent'
    }

    function maybeFetchImageModels(context, suppressErrors) {
        if (!context || !imageModeIsIndependent()) {
            return
        }
        var $modelSelect = $('.quorlyx-image-model-select[data-context="' + context + '"]');
        var $provider = $('.quorlyx-image-provider-select[data-context="' + context + '"]');
        var $apiInput = $('.quorlyx-image-api-key-input[data-context="' + context + '"]');
        if (!$modelSelect.length || !$provider.length || !$apiInput.length) {
            return
        }
        var provider = $provider.val();
        var apiKey = $apiInput.val();
        if (!provider || !apiKey) {
            if (!suppressErrors) {
                handleModelFetchError($modelSelect, 'Enter API key to fetch models.')
            }
            return
        }
        fetchImageModels(context, provider, apiKey)
    }

    function fetchImageModels(context, provider, apiKey) {
        var $modelSelect = $('.quorlyx-image-model-select[data-context="' + context + '"]');
        if (!$modelSelect.length) {
            return
        }
        var $spinner = $modelSelect.next('.quorlyx-image-model-spinner');
        $spinner.addClass('is-active');
        $modelSelect.prop('disabled', true).empty().append('<option>Fetching models...</option>');
        $.ajax({
            url: quorlyxAdmin.restUrl + 'fetch-models',
            method: 'POST',
            contentType: 'application/json',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: JSON.stringify({
                provider: provider,
                api_key: apiKey,
                mode: 'image'
            })
        }).done(function(response) {
            if (response.success && response.models.length) {
                $modelSelect.empty();
                var savedModel = $modelSelect.data('saved-model') || '';
                var isSavedModelPresent = false;
                response.models.forEach(function(model) {
                    var optionText = model.name;
                    var $option = $('<option>', {
                        value: model.id,
                        text: optionText
                    });
                    if (model.id === savedModel) {
                        $option.prop('selected', true);
                        isSavedModelPresent = true
                    }
                    $modelSelect.append($option)
                });
                if (!isSavedModelPresent && savedModel) {
                    $modelSelect.append($('<option>', {
                        value: savedModel,
                        text: savedModel,
                        selected: true
                    }))
                }
                if (!isSavedModelPresent && response.models.some(m => m.name.toLowerCase().includes('recommended'))) {
                    $modelSelect.val($modelSelect.find('option:contains(Recommended)').val())
                }
            } else {
                handleModelFetchError($modelSelect, 'No compatible models found.')
            }
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Could not fetch models.';
            handleModelFetchError($modelSelect, message)
        }).always(function() {
            $spinner.removeClass('is-active');
            $modelSelect.prop('disabled', false)
        })
    }

    function initImageModelAutoFetch() {
        var initializedContexts = [];
        $('.quorlyx-image-model-select').each(function() {
            var context = $(this).data('context');
            if (context && initializedContexts.indexOf(context) === -1) {
                initializedContexts.push(context);
                maybeFetchImageModels(context, true)
            }
        });
        $('.postbox').on('change', '.quorlyx-image-provider-select', function() {
            var context = $(this).data('context');
            maybeFetchImageModels(context)
        });
        $('.postbox').on('blur', '.quorlyx-image-api-key-input', function() {
            var context = $(this).data('context');
            maybeFetchImageModels(context)
        })
    }

    $('.quorlyx-provider-select').each(function() {
        syncProviderUI(this)
    });
    $('.postbox').on('change', '.quorlyx-provider-select', function() {
        syncProviderUI(this)
    });
    initRoutingModelFetch();
    $('body').on('change', '.quorlyx-routing-provider-select', function() {
        initRoutingModelFetch()
    });
    $('.postbox').on('blur', '.quorlyx-api-key-input', function() {
        var $input = $(this);
        var apiKey = $input.val();
        var provider = $input.data('provider');
        var variation = $input.data('variation');
        if (apiKey) {
            fetchModelsForProvider(variation, provider, apiKey);
            var $routingProvider = $('.quorlyx-routing-provider-select');
            if ($routingProvider.length && variation === 'a' && $routingProvider.val() === provider) {
                fetchModelsForRouting(provider, apiKey)
            }
        }
    });
    initImageModelAutoFetch();

    // --- General Settings UI ---
    $('#ab_testing_enabled_toggle').on('change', function() {
        var $variationB = $('#variation_b_wrap');
        if (this.checked) {
            $variationB.addClass('active').show();
            $('.settings-main-area').css({
                'grid-template-columns': '1fr 1fr'
            });
        } else {
            $variationB.removeClass('active').hide();
            $('.settings-main-area').css({
                'grid-template-columns': '1fr'
            });
        }
    }).trigger('change');

    $('#quorlyx_trigger_type').on('change', function() {
        var selectedType = $(this).val();
        $('#trigger_type_options .trigger-option').hide();
        $('#' + selectedType + '_options').show()
    }).trigger('change');

    // --- Unified Repeater Logic (No AJAX) ---
    function setItemState($item, state) {
        $item.attr('data-state', state);
    }

    function reindexItems($container, nameAttribute) {
        $container.children().each(function(index) {
            var $item = $(this);
            $item.find('[name]').each(function() {
                var currentName = $(this).attr('name');
                var newName = currentName.replace(new RegExp('\\[' + nameAttribute + '\\]\\[.*?\\]'), '[' + nameAttribute + '][' + index + ']');
                $(this).attr('name', newName);
            });
        });
    }

    // Initialize state for all repeater-like items
    $('.quorlyx-repeater-item, .quorlyx-goal-item').each(function() {
        var initialState = $(this).attr('data-state');
        setItemState($(this), initialState);
    });

    // Add new Quick Chat button
    $('body').on('click', '.quorlyx-add-repeater-item', function() {
        var $container = $(this).closest('.quorlyx-repeater-container');
        var $repeaterItems = $container.find('.quorlyx-repeater-items');
        var variation = $repeaterItems.data('variation');
        var index = $repeaterItems.children().length;

        var template = $container.find('.quorlyx-repeater-template').html()
            .replace(/__INDEX__/g, index)
            .replace(/variation_.__/g, 'variation_' + variation);

        var $newItem = $(template);
        $repeaterItems.append($newItem);
        setItemState($newItem, 'edit');
    });

    // Add new Conversion Goal
    $('#quorlyx-add-goal').on('click', function() {
        var $container = $('#quorlyx-goals-container');
        var index = $container.children().length;
        var template = $('#quorlyx-goal-template').html().replace(/__INDEX__/g, index);
        var $newItem = $(template);
        $container.append($newItem);
        setItemState($newItem, 'edit');
    });

    // Generic 'Done' button for all repeaters
    $('body').on('click', '.quorlyx-done-item', function() {
        var $item = $(this).closest('.quorlyx-repeater-item, .quorlyx-goal-item');
        var $labelField = $item.find('.quorlyx-action-label, .quorlyx-goal-name');
        var label = $labelField.val();

        if (!label || label.trim() === '') {
            alert('Label or Name is required.');
            $labelField.focus();
            return;
        }

        $item.find('.quorlyx-item-label').text(label);
        setItemState($item, 'view');
    });

    // Generic 'Edit' button for all repeaters
    $('body').on('click', '.quorlyx-edit-item', function() {
        var $item = $(this).closest('.quorlyx-repeater-item, .quorlyx-goal-item');
        setItemState($item, 'edit');
    });

    // Generic 'Remove' button for all repeaters
    $('body').on('click', '.quorlyx-remove-item', function() {
        if (!confirm('Are you sure you want to remove this item? This cannot be undone until you save changes.')) return;

        var $item = $(this).closest('.quorlyx-repeater-item, .quorlyx-goal-item');
        var $container = $item.parent();
        var isGoal = $item.hasClass('quorlyx-goal-item');

        $item.fadeOut(300, function() {
            $(this).remove();
            if (isGoal) {
                reindexItems($container, 'conversion_goals');
            } else {
                reindexItems($container, 'actions');
            }
        });
    });

    // Handle type change for Quick Chat buttons
    $('body').on('change', '.quorlyx-action-type', function() {
        var type = $(this).val();
        var $editor = $(this).closest('.quorlyx-item-editor');
        $editor.find('.quorlyx-action-target').toggle(type === 'url');
        $editor.find('.quorlyx-action-message').toggle(type === 'message');
        $editor.find('.quorlyx-action-context').toggle(type === 'message');
    });

    // --- Media Uploader ---
    $('body').on('click', '.quorlyx-media-uploader .upload-button', function(e) {
        e.preventDefault();
        var $uploader = $(this).closest('.quorlyx-media-uploader');
        var frame = wp.media({
            title: 'Select Logo',
            button: {
                text: 'Use this logo'
            },
            multiple: false
        });
        frame.on('select', function() {
            var attachment = frame.state().get('selection').first().toJSON();
            $uploader.find('.media-url').val(attachment.url);
            $uploader.find('.image-preview-wrapper').html('<img src="' + attachment.url + '" style="max-width:64px;max-height:64px;border-radius:50%;">');
            $uploader.find('.remove-button').show()
        });
        frame.open()
    });
    $('body').on('click', '.quorlyx-media-uploader .remove-button', function(e) {
        e.preventDefault();
        var $uploader = $(this).closest('.quorlyx-media-uploader');
        $uploader.find('.media-url').val('');
        $uploader.find('.image-preview-wrapper').html('');
        $(this).hide()
    });

    // --- Content Engine AJAX ---
    function showGenerationStatus($statusDiv, response) {
        $statusDiv.removeClass('notice-success notice-error').hide();
        if (response) {
            $statusDiv.addClass(response.success ? 'notice-success' : 'notice-error');
            var content = response.analysis ? response.analysis.replace(/\n/g, '<br>') : response.message || '';
            $statusDiv.html(content);
            $statusDiv.show()
        }
    }

    function generatePostNow() {
        return $.ajax({
            url: quorlyxAdmin.restUrl + 'generate-post-now',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            }
        })
    }
    $('#quorlyx_generate_keywords_button').on('click', function() {
        var $button = $(this);
        var description = $('#quorlyx_keyword_business_description').val();
        if (description.trim()) {
            $button.prop('disabled', true).next('.spinner').addClass('is-active');
            $.ajax({
                url: quorlyxAdmin.restUrl + 'generate-keywords',
                method: 'POST',
                beforeSend: function(xhr) {
                    xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
                },
                data: {
                    description: description
                },
                success: function(response) {
                    var $keywordsTextarea = $('#quorlyx_post_generator_keywords');
                    var currentKeywords = $keywordsTextarea.val().trim();
                    var newKeywords = response.keywords.trim();
                    $keywordsTextarea.val(currentKeywords ? currentKeywords + '\n' + newKeywords : newKeywords)
                },
                error: function(jqXHR) {
                    var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
                    alert('Error generating keywords: ' + message)
                },
                complete: function() {
                    $button.prop('disabled', false).next('.spinner').removeClass('is-active')
                }
            })
        } else {
            alert('Please provide a business description first.')
        }
    });
    $('#quorlyx_generate_post_now_button, #quorlyx_generate_post_now_button_dashboard').on('click', function() {
        var buttonId = $(this).attr('id');
        var $button = $('#' + buttonId);
        var $statusDiv = buttonId === 'quorlyx_generate_post_now_button' ? $('#quorlyx-post-generation-status') : $('#quorlyx-dashboard-generation-status');
        $button.prop('disabled', true).next('.spinner').addClass('is-active');
        $statusDiv.hide();
        generatePostNow().done(function(response) {
            showGenerationStatus($statusDiv, {
                success: true,
                message: response.message
            })
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
            showGenerationStatus($statusDiv, {
                success: false,
                message: '<strong>Error:</strong> ' + message
            })
        }).always(function() {
            $button.prop('disabled', false).next('.spinner').removeClass('is-active')
        })
    });
    $('#quorlyx_analyze_topic_button').on('click', function() {
        var $button = $(this);
        var $statusDiv = $('#quorlyx-topic-analysis-results');
        var topic = $('#quorlyx_topic_analysis_input').val();
        if (!topic.trim()) {
            alert('Please enter a topic to analyze.');
            return
        }
        $button.prop('disabled', true).next('.spinner').addClass('is-active');
        $statusDiv.hide();
        $.ajax({
            url: quorlyxAdmin.restUrl + 'analyze-topic',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: {
                topic: topic
            }
        }).done(function(response) {
            showGenerationStatus($statusDiv, {
                success: true,
                analysis: response.analysis
            })
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
            showGenerationStatus($statusDiv, {
                success: false,
                message: '<strong>Error:</strong> ' + message
            })
        }).always(function() {
            $button.prop('disabled', false).next('.spinner').removeClass('is-active')
        })
    });
    var seoSuggestionStore = quorlyxAdmin && Array.isArray(quorlyxAdmin.seoSuggestions) ? quorlyxAdmin.seoSuggestions.slice() : [];
    function escapeHtml(str) {
        return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;')
    }
    function formatSuggestionAnalysis(text) {
        return escapeHtml(text).replace(/\n/g, '<br>')
    }
    function renderSeoSuggestionList() {
        var $list = $('#quorlyx-seo-suggestion-list');
        if (!$list.length) return;
        if (!seoSuggestionStore.length) {
            $list.html('<div class="quorlyx-seo-suggestion-empty">Saved SEO suggestions will appear here.</div>');
            return
        }
        var html = seoSuggestionStore.map(function(item) {
            var isPost = item && item.target_type === 'post' && Number(item.post_id || 0) > 0;
            var improved = !!(item && item.is_improved);
            var badges = '<span class="quorlyx-seo-badge">' + escapeHtml(item.label || (isPost ? 'Content' : 'Bulk Scope')) + '</span>';
            badges += item && item.is_generated ? '<span class="quorlyx-seo-badge">AI</span>' : '<span class="quorlyx-seo-badge">Manual</span>';
            if (improved) {
                badges += '<span class="quorlyx-seo-badge quorlyx-seo-badge-success">Improved</span>'
            }
            var actions = '';
            if (isPost) {
                actions += '<button type="button" class="button button-small quorlyx-toggle-improved" data-post-id="' + escapeHtml(item.post_id) + '" data-improved="' + (improved ? '1' : '0') + '">' + (improved ? 'Remove Improved Tag' : 'Mark as Improved') + '</button>'
            }
            actions += '<button type="button" class="button button-small quorlyx-delete-seo-suggestion" data-suggestion-id="' + escapeHtml(item.id || '') + '">Delete</button>';
            var meta = item && item.url ? '<a class="quorlyx-seo-suggestion-link" href="' + escapeHtml(item.url) + '" target="_blank" rel="noopener noreferrer">Open content</a>' : '';
            return '<article class="quorlyx-seo-suggestion-card" data-suggestion-id="' + escapeHtml(item.id || '') + '">' + '<header class="quorlyx-seo-suggestion-card-header"><div><h6>' + escapeHtml(item.title || 'SEO Suggestion') + '</h6><div class="quorlyx-seo-suggestion-badges">' + badges + '</div></div><div class="quorlyx-seo-suggestion-meta">' + meta + '</div></header>' + '<div class="quorlyx-seo-suggestion-card-body">' + formatSuggestionAnalysis(item.analysis || '') + '</div>' + '<div class="quorlyx-seo-suggestion-card-actions">' + actions + '</div>' + '</article>'
        }).join('');
        $list.html(html)
    }
    function updateSeoImprovementTargetFilters() {
        var term = String($('#quorlyx_seo_improvement_search').val() || '').toLowerCase();
        var sourceFilter = String($('#quorlyx_seo_improvement_source_filter').val() || 'any');
        var improvedFilter = String($('#quorlyx_seo_improvement_improved_filter').val() || 'any');
        $('.quorlyx-seo-improvement-target-option').each(function() {
            var $option = $(this);
            var label = String($option.data('label') || '');
            var isGenerated = String($option.attr('data-generated') || '0') === '1';
            var isImproved = String($option.attr('data-improved') || '0') === '1';
            var sourceMatches = sourceFilter === 'any' || (sourceFilter === 'ai_generated' && isGenerated) || (sourceFilter === 'manual' && !isGenerated);
            var improvedMatches = improvedFilter === 'any' || (improvedFilter === 'improved' && isImproved) || (improvedFilter === 'not_improved' && !isImproved);
            var termMatches = term === '' || label.indexOf(term) !== -1;
            $option.toggle(sourceMatches && improvedMatches && termMatches)
        })
    }
    function syncSeoTargetOption(postId, improved) {
        var normalizedPostId = String(postId || '');
        if (!normalizedPostId) return;
        $('.quorlyx-seo-improvement-target-option').each(function() {
            var $option = $(this);
            var $checkbox = $option.find('.quorlyx-seo-improvement-checkbox');
            if (String($checkbox.val() || '') !== normalizedPostId) {
                return
            }
            $option.attr('data-improved', improved ? '1' : '0');
            var $badges = $option.find('.quorlyx-seo-improvement-target-badges');
            $badges.find('.quorlyx-seo-badge-success').remove();
            if (improved) {
                $badges.append('<span class="quorlyx-seo-badge quorlyx-seo-badge-success">Improved</span>')
            }
        });
        updateSeoImprovementTargetFilters()
    }
    renderSeoSuggestionList();
    $(document).on('input change', '#quorlyx_seo_improvement_search, #quorlyx_seo_improvement_source_filter, #quorlyx_seo_improvement_improved_filter', updateSeoImprovementTargetFilters);
    updateSeoImprovementTargetFilters();
    $('#quorlyx_suggest_seo_improvements_button').on('click', function() {
        var $button = $(this);
        var $statusDiv = $('#quorlyx-seo-improvement-results');
        var checkedValues = $('.quorlyx-seo-improvement-checkbox:checked').map(function() {
            return String($(this).val() || '')
        }).get();
        if (!checkedValues.length) {
            alert('Please choose one or more targets first.');
            return
        }
        var data = {
            post_ids: [],
            target_scopes: []
        };
        checkedValues.forEach(function(value) {
            if (0 === value.indexOf('scope:')) {
                data.target_scopes.push(value.replace('scope:', ''))
            } else {
                data.post_ids.push(value)
            }
        });
        $button.prop('disabled', true).next('.spinner').addClass('is-active');
        $statusDiv.hide();
        $.ajax({
            url: quorlyxAdmin.restUrl + 'suggest-seo-improvements',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: data
        }).done(function(response) {
            seoSuggestionStore = response && Array.isArray(response.suggestions) ? response.suggestions.slice() : seoSuggestionStore;
            renderSeoSuggestionList();
            showGenerationStatus($statusDiv, {
                success: true,
                message: (Number(response.generated_count || 0) || data.post_ids.length || data.target_scopes.length) + ' SEO suggestion card(s) saved in the panel.'
            })
        }).fail(function(jqXHR) {
            var message = jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'An unknown error occurred.';
            showGenerationStatus($statusDiv, {
                success: false,
                message: '<strong>Error:</strong> ' + message
            })
        }).always(function() {
            $button.prop('disabled', false).next('.spinner').removeClass('is-active')
        })
    });
    $('body').on('click', '.quorlyx-delete-seo-suggestion', function() {
        var suggestionId = String($(this).data('suggestion-id') || '');
        if (!suggestionId) return;
        $.ajax({
            url: quorlyxAdmin.restUrl + 'delete-seo-suggestion',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: {
                suggestion_id: suggestionId
            }
        }).done(function(response) {
            seoSuggestionStore = response && Array.isArray(response.suggestions) ? response.suggestions.slice() : [];
            renderSeoSuggestionList()
        }).fail(function(jqXHR) {
            alert(jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Could not delete this suggestion.')
        })
    });
    $('body').on('click', '.quorlyx-toggle-improved', function() {
        var $button = $(this);
        var postId = Number($button.data('post-id') || 0);
        var improved = String($button.data('improved') || '0') !== '1';
        if (!postId) return;
        $button.prop('disabled', true);
        $.ajax({
            url: quorlyxAdmin.restUrl + 'set-seo-improved-status',
            method: 'POST',
            beforeSend: function(xhr) {
                xhr.setRequestHeader('X-WP-Nonce', quorlyxAdmin.nonce)
            },
            data: {
                post_id: postId,
                improved: improved ? '1' : '0'
            }
        }).done(function(response) {
            seoSuggestionStore = response && Array.isArray(response.suggestions) ? response.suggestions.slice() : seoSuggestionStore;
            renderSeoSuggestionList();
            syncSeoTargetOption(postId, !!response.improved)
        }).fail(function(jqXHR) {
            alert(jqXHR.responseJSON && jqXHR.responseJSON.message ? jqXHR.responseJSON.message : 'Could not update improved status.')
        }).always(function() {
            $button.prop('disabled', false)
        })
    });

    // --- Tour Restart Logic ---
    $('#quorlyx-restart-tour').on('click', function(e) {
        e.preventDefault();
        // Always start the tour from the dashboard using a prebuilt safe URL
        try {
            var url = (quorlyxAdmin && quorlyxAdmin.dashboard_url_start_tour) ? quorlyxAdmin.dashboard_url_start_tour : null;
            if (!url) {
                // Fallback: minimal risk of malformed URL but keeps UX working
                var base = (quorlyxAdmin && quorlyxAdmin.dashboard_url) ? quorlyxAdmin.dashboard_url : 'admin.php?page=quorlyx-dashboard';
                url = base + (base.indexOf('?') !== -1 ? '&' : '?') + 'start_tour=true';
            }
            window.location.href = url;
        } catch (err) {
            window.location.href = 'admin.php?page=quorlyx-dashboard&start_tour=true';
        }
    });
    // --- Permanent Dismiss Handler for Notices ---
    $('body').on('click', '.quorlyx-dismiss-forever', function(e) {
        e.preventDefault();
        var $btn = $(this);
        var noticeId = $btn.data('notice');
        if (!noticeId) return;
        var $notice = $btn.closest('.notice');
        $btn.prop('disabled', true);
        $.post(quorlyxAdmin.ajax_url, {
            action: 'quorlyx_dismiss_notice',
            notice_id: noticeId,
            nonce: quorlyxAdmin.dismissNonce
        }, function(response) {
            if (response && response.success) {
                $notice.slideUp(180, function() {
                    $(this).remove();
                });
            } else {
                alert('Failed to dismiss notice.');
                $btn.prop('disabled', false);
            }
        }).fail(function() {
            alert('Failed to dismiss notice.');
            $btn.prop('disabled', false);
        });
    });

    function togglePostGenProvider() {
        var $mode = $('#quorlyx_post_generator_ai_mode');
        if (!$mode.length) return;
        var mode = $mode.val();
        var $rows = $('.quorlyx-postgen-independent-row');
        var independent = mode === 'independent';
        independent ? $rows.show() : $rows.hide();
        $rows.find('.quorlyx-postgen-required').each(function() {
            if (independent) {
                $(this).attr('required', 'required');
            } else {
                $(this).removeAttr('required');
            }
        });
    }
    togglePostGenProvider();
    $('body').on('change', '#quorlyx_post_generator_ai_mode', togglePostGenProvider);

    function toggleImageProvider() {
        var $mode = $('#quorlyx_image_generator_ai_mode');
        if (!$mode.length) return;
        var mode = $mode.val();
        var $rows = $('.quorlyx-image-independent-row');
        var independent = mode === 'independent';
        independent ? $rows.show() : $rows.hide();
        if (independent) {
            maybeFetchImageModels('postgen_images', true);
        }
        $rows.find('.quorlyx-image-required').each(function() {
            if (independent) {
                $(this).attr('required', 'required');
            } else {
                $(this).removeAttr('required');
            }
        });
    }
    toggleImageProvider();
    $('body').on('change', '#quorlyx_image_generator_ai_mode', toggleImageProvider);
});
